#include<bits/stdc++.h>
using namespace std;
int main() {
	int i,n,a[10001],e=1,maxa=0;
	cin>>n;
	for(i=0;i<n;i++){
		cin>>a[i];}
	for(i=0;i<n;i++){
		maxa=max(a[i],maxa);
	}i=0;	
	while(1){
		e=1;
		for(int j=0;j<n;j++){
			if(i%a[j]!=0){
				e=0;
			}
		}if(e==1&&i!=0){
			cout<<i;
			return 0;
		}i+=maxa;
	}
}
